import { LinearGradient } from 'expo-linear-gradient';
import React, { useContext, useCallback, useEffect } from 'react';
import { useSelector, useDispatch } from "react-redux";
import { View, Text, Image, TouchableOpacity } from 'react-native';
import { useFocusEffect } from '@react-navigation/native';
import { Ionicons } from '@expo/vector-icons';
import styles from '../styles';
import * as Animatable from 'react-native-animatable';
import COLORS from '../colors';
import { SocketContext } from '../helpers/SocketContext';
import { setEmergency } from '../redux/ducks/auto';

const Stats = ({ navigation, location }) => {
    const socket = useContext(SocketContext);
    const { emergency, reset, zeroref } = useSelector(state => state.auto);

    const [action, setAction] = React.useState(0);
    const [error, setError] = React.useState(false);
    const [status, setStatus] = React.useState(false);
    const [fault, setFault] = React.useState(false);
    const [ethercatA, setEthercatA] = React.useState(false);
    const [msg, setMsg] = React.useState('No Errors');

    const [ecs, setecs] = React.useState(false);
    const [fin, setfin] = React.useState(false);
    const [sol_op, setsol_op] = React.useState(false);
    const [cl, setcl] = React.useState(false);
    const [dcl, setdcl] = React.useState(false);
    const [alm_in, setalm_in] = React.useState(false);
    const [alm_out, setalm_out] = React.useState(false);
    const [home, sethome] = React.useState(false);
    const [pot, setpot] = React.useState(false);
    const [not, setnot] = React.useState(false);

    const [pos, setPos] = React.useState('');
    const [dest, setDest] = React.useState('');
    const [driveError, setDriveError] = React.useState('0');

    const dispatch = useDispatch();

    const handleAlarm = (data) => {
        if (data == 'No Alarms') {
            setError(false);
            setFault(false);
            setMsg(data);
            setDriveError('0'); // Reset drive error to 0
        }
        else {
            setMsg(data);
            setFault(true);

            // Extract number from the alarm message for the drive error display
            const errorCode = data.match(/\d+/) || ['0'];
            setDriveError(errorCode[0]);

            if (!error && !status) {
                setError(true);
            }
        }
    };
    const handlePos = useCallback(data => setPos(data.data), []);
    const handleDest = useCallback(data => setDest(data.pos), []);
    const handleDriver = useCallback(data => {
        if (data.drive_name == 'A') {
            setEthercatA(data.status == 1 ? true : false);
        }
    }, []);
    const handleIO = useCallback(data => {
        setecs(data.ioStat.ecs);
        setfin(data.ioStat.fin);
        setsol_op(data.ioStat.sol_op);
        setcl(data.ioStat.cl);
        setdcl(data.ioStat.dcl);
        setalm_in(data.ioStat.alm_in);
        setalm_out(data.ioStat.alm_out);
        sethome(data.ioStat.home);
        setpot(data.ioStat.pot);
        setnot(data.ioStat.not);
    }, []);

    const handleDriveError = useCallback(data => setDriveError(data.code), []);
    const handleSend = useCallback((ev, req) => {
        socket.emit(ev, req);
    }, []);

    const handleEnableEmergency = () => {
        dispatch(setEmergency(false, reset, zeroref))
    }
    const handleEnableReset = () => {
        dispatch(setEmergency(false, false, false))
    }
    const handleEnableZeroref = () => {
        dispatch(setEmergency(emergency, reset, false))
    }

    useFocusEffect(
        React.useCallback(() => {
            return () => {
                setError(false);
                setStatus(false);
            };
        }, [])
    );

    useEffect(() => {
        socket.on("alarm_error", handleAlarm);
        socket.on("pos_data", handlePos);
        socket.on("destination_position", handleDest);
        socket.on("io_status", handleIO);
        socket.on("driver_status", handleDriver);
        socket.on("drive_error_code", handleDriveError);

        socket.on("gotozero_done", handleEnableZeroref);
        socket.on("emergency_done", handleEnableEmergency);
        socket.on("reset_done", handleEnableReset);

        return () => {
            socket.off("alarm_error", handleAlarm);
            socket.off("pos_data", handlePos);
            socket.off("destination_position", handleDest);
            socket.off("io_status", handleIO);
            socket.off("driver_status", handleDriver);

            socket.off("gotozero_done", handleEnableZeroref);
            socket.off("emergency_done", handleEnableEmergency);
            socket.off("reset_done", handleEnableReset);
        };
    }, [socket, handleAlarm, handlePos, handleDest, handleIO, handleDriver, handleEnableZeroref, handleEnableEmergency, handleEnableReset]);

    return (
        <>
            <LinearGradient colors={['#2d2c2d', '#000']} style={styles.statsWrap}>
                <View style={styles.stats1}>
                    {location == 'MANUAL' && <Image source={require('../img/home/manual.png')} style={styles.icnStatMain} />}
                    {location == 'PROGRAM' && <Image source={require('../img/home/program.png')} style={styles.icnStatMain} />}
                    {location == 'AUTO' && <Image source={require('../img/home/auto.png')} style={styles.icnStatMain} />}
                    {location == 'SETTINGS' && <Image source={require('../img/home/settings.png')} style={styles.icnStatMain} />}
                    <Text style={[styles.title1, styles.mt5]}>{location}</Text>
                </View>
                <View style={styles.stats2}>
                    <View style={[{ alignItems: 'center' }, styles.flex1]}>
                        <Text style={[styles.titleStat1, styles.mr5, styles.mb15]}>EN</Text>
                        <View style={[styles.statusGreen]} />
                    </View>
                    <View style={[{ alignItems: 'center' }, styles.flex1]}>
                        <Text style={[styles.titleStat1, styles.ml5, styles.mb15]}>AXIS</Text>
                        <View style={[styles.bgText0, styles.ml5]}>
                            <Text style={styles.txtStatsActive}>B</Text>
                        </View>
                    </View>
                </View>
                <View style={styles.stats3}>
                    <View style={[styles.rowCenter, styles.mb15]}>
                        <Text style={[styles.titleStat1, styles.mr10, styles.textRight, styles.flex1]}>ACTUAL POSITION</Text>
                        <Text style={[styles.titleStat1, styles.ml10, styles.textLeft, styles.flex1]}>DESTINATION</Text>
                    </View>
                    <View style={[styles.rowCenter, styles.my5]}>
                        <View style={[styles.bgText1, styles.mr15]}>
                            <Text style={[styles.txtStatsActive, styles.selfEnd]}> {dest}</Text>
                        </View>
                        <View style={{
                            width: 1,
                            height: 40,
                            backgroundColor: '#888',  // or COLORS.gray if defined
                            marginHorizontal: 15,
                        }} />
                        <View style={[styles.bgText1, styles.ml15]}>
                            <Text style={[styles.txtStatsActive, styles.selfStart]}>{pos} </Text>
                        </View>
                    </View>
                </View>
                <View style={[{ alignItems: 'center', justifyContent: 'center',marginTop: 15, marginLeft: 20 }, /*styles.flex1, { paddingHorizontal: 10 }*/]}>
                    <Text style={[styles.titleStat1, styles.mb15]}>DRIVE ERROR</Text>
                    <View style={[styles.bgText1]}>
                        <Text style={[styles.txtStatsActive, { paddingHorizontal: 20, paddingVertical: 2 }]}>{driveError}</Text>
                    </View>
                </View>
                
                <View style={styles.stats4}>
                    <TouchableOpacity onPress={() => {
                        if (status) { setStatus(false); }
                        setError(!error);
                    }} style={[{ alignItems: 'center' }, styles.flex1]}>
                        <Text style={[styles.titleStat1, styles.mr5, styles.mb15]}>FAULT</Text>
                        <View style={fault ? styles.statusRed : styles.statusGreen} />
                    </TouchableOpacity>
                    <TouchableOpacity onPress={() => {
                        if (error) { setError(false); };
                        setStatus(!status);
                    }} style={[{ alignItems: 'center' }, styles.flex1]}>
                        <Text style={[styles.titleStat1, styles.ml5, styles.mb15]}>I/O</Text>
                        <View style={[styles.statusGreen]} />
                    </TouchableOpacity>
                </View>
                <View style={styles.stats5}>
                    <TouchableOpacity style={[styles.mb5, { opacity: emergency || reset ? 0.5 : 1 }]} disabled={emergency || reset} onPress={() => {
                        handleSend('emergency', { "action": action == 0 ? 1 : 0 });
                        setAction(action == 0 ? 1 : 0);
                        dispatch(setEmergency(true, false, true));
                    }}>
                        <LinearGradient colors={[COLORS.red1, COLORS.red2]} style={styles.btnStat}>
                            <Ionicons name="warning" size={20} color="#fffa" style={styles.mr10} />
                            <Text style={styles.btnTxtRed}>EMERGENCY</Text>
                        </LinearGradient>
                    </TouchableOpacity>
                    <TouchableOpacity style={{ opacity: reset ? 0.5 : 1 }} disabled={reset} onPress={() => {
                        handleSend('reset', { "status": "clear" });
                        dispatch(setEmergency(true, true, true));
                    }}>
                        <LinearGradient colors={[COLORS.blue1, COLORS.blue2]} style={styles.btnStat}>
                            <Ionicons name="ios-sync-outline" size={20} color="#fffa" style={styles.mr10} />
                            <Text style={styles.btnTxtRed}>RESET</Text>
                        </LinearGradient>
                    </TouchableOpacity>
                </View>
            </LinearGradient>


            {status &&
                <Animatable.View style={styles.modalWrap} animation="slideInUp" duration={300}>
                    <LinearGradient colors={[COLORS.modal1, COLORS.modal2]} style={styles.w100p}>
                        <View style={styles.modalInner}>
                            <View style={styles.modalHeader}>
                                <View style={styles.row0Start}>
                                    <Text style={styles.body1}>I/O STATUS</Text>
                                </View>
                                <TouchableOpacity style={[styles.pl20, styles.py15]} onPress={() => { setStatus(false); }}>
                                    <Ionicons name="ios-close" size={20} color="#fffa" style={styles.mr10} />
                                </TouchableOpacity>
                            </View>
                            <View style={styles.modalBody}>
                                <View style={styles.rowBetween}>
                                    <View style={styles.itemsCenter}>
                                        <Text style={[styles.body1, styles.mb20]}>ECS</Text>
                                        <View style={ecs === true ? styles.statusGreen : styles.statusNone} />
                                    </View>
                                    <View style={styles.itemsCenter}>
                                        <Text style={[styles.body1, styles.mb20]}>FIN</Text>
                                        <View style={fin === true ? styles.statusGreen : styles.statusNone} />
                                    </View>
                                    <View style={styles.itemsCenter}>
                                        <Text style={[styles.body1, styles.mb20]}>SOL O/P</Text>
                                        <View style={sol_op === true ? styles.statusGreen : styles.statusNone} />
                                    </View>
                                    <View style={styles.itemsCenter}>
                                        <Text style={[styles.body1, styles.mb20]}>CL</Text>
                                        <View style={cl === true ? styles.statusGreen : styles.statusNone} />
                                    </View>
                                    <View style={styles.itemsCenter}>
                                        <Text style={[styles.body1, styles.mb20]}>DCL</Text>
                                        <View style={dcl === true ? styles.statusGreen : styles.statusNone} />
                                    </View>
                                    <View style={styles.itemsCenter}>
                                        <Text style={[styles.body1, styles.mb20]}>ALM-IN</Text>
                                        <View style={alm_in === true ? styles.statusGreen : styles.statusNone} />
                                    </View>
                                    <View style={styles.itemsCenter}>
                                        <Text style={[styles.body1, styles.mb20]}>ALM-OUT</Text>
                                        <View style={alm_out === true ? styles.statusGreen : styles.statusNone} />
                                    </View>
                                    <View style={styles.itemsCenter}>
                                        <Text style={[styles.body1, styles.mb20]}>HOME</Text>
                                        <View style={home === true ? styles.statusGreen : styles.statusNone} />
                                    </View>
                                    <View style={styles.itemsCenter}>
                                        <Text style={[styles.body1, styles.mb20]}>POT</Text>
                                        <View style={pot === true ? styles.statusGreen : styles.statusNone} />
                                    </View>
                                    <View style={styles.itemsCenter}>
                                        <Text style={[styles.body1, styles.mb20]}>NOT</Text>
                                        <View style={not === true ? styles.statusGreen : styles.statusNone} />
                                    </View>
                                </View>
                            </View>
                        </View>
                    </LinearGradient>
                </Animatable.View>}


            {error &&
                <Animatable.View style={styles.modalWrap} animation="slideInUp" duration={300}>
                    <LinearGradient colors={[COLORS.modal1, COLORS.modal2]} style={styles.w100p}>
                        <View style={styles.modalInner}>
                            <View style={styles.modalHeader}>
                                <View style={styles.row0Start}>
                                    <Ionicons name="notifications-outline" size={20} color="#fffa" style={styles.mr10} />
                                    <Text style={styles.body1}>ALARM STATUS</Text>
                                </View>
                                <TouchableOpacity style={[styles.pl20, styles.py15]} onPress={() => { setError(false); }}>
                                    <Ionicons name="ios-close" size={20} color="#fffa" style={styles.mr10} />
                                </TouchableOpacity>
                            </View>
                            <View style={styles.modalBody}>
                                <View style={styles.rowBetween}>
                                    <Text style={[styles.body1, styles.mr20]}>
                                        ALARMS/ ERRORS
                                    </Text>
                                    <View style={styles.alarmBg}>
                                        <Text style={styles.body3}>
                                            {msg}
                                        </Text>
                                    </View>
                                </View>
                            </View>
                        </View>
                    </LinearGradient>
                </Animatable.View>}
        </>
    );
};

export default Stats;