import React, { useContext, useState, useCallback, useEffect } from 'react';
import { View, Text, Image, TouchableOpacity, ImageBackground, Dimensions } from 'react-native';
import { LinearGradient } from 'expo-linear-gradient';
import { Ionicons } from '@expo/vector-icons';
const { width, height } = Dimensions.get('window');
import { useSelector, useDispatch } from "react-redux";
import { useFocusEffect } from '@react-navigation/native';

import styles from '../../styles';
import COLORS from '../../colors';
import { SocketContext } from '../../helpers/SocketContext';

import { setEmergency, setJog } from '../../redux/ducks/auto';

import Stats from '../../components/Stats'
import api from '../../helpers/Api';

const Manual = ({ navigation }) => {
  const socket = useContext(SocketContext);

  const [mode, setMode] = useState('JOG');
  const [position, setPosition] = useState(0.1);
  const [direction, setDirection] = useState(1);
  const [action, setAction] = useState(0);
  const [modal, setModal] = useState(false);
  const dispatch = useDispatch();

  const [moving, setMoving] = useState(false);

  const [loading, setLoading] = useState(false);
  const [zeroRef, setZeroRef] = useState(true);

  const { running, jog, emergency, reset, zeroref } = useSelector(state => state.auto);

  const handleSend = useCallback((ev, req) => {
    socket.emit(ev, req);
  }, []);

  const handleStep = useCallback(data => {
    setMoving(false);
  }, []);

  const handleEnableEmergency = () => {
    dispatch(setEmergency(false, reset, zeroref))
  }
  const handleEnableReset = () => {
    dispatch(setEmergency(false, false, false))
  }
  const handleEnableZeroref = () => {
    dispatch(setEmergency(emergency, reset, false))
  }

  useFocusEffect(
    useCallback(() => {
      setModal(running);
    }, [running])
  );
  //console.log("emergency, reset, zeroref ", emergency, reset, zeroref);
  useEffect(() => {
    socket.on("step_mode_completed", handleStep);
    socket.on("gotozero_done", handleEnableZeroref);
    socket.on("emergency_done", handleEnableEmergency);
    socket.on("reset_done", handleEnableReset);
    return () => {
      socket.off("step_mode_completed", handleStep);
      socket.off("gotozero_done", handleEnableZeroref);
      socket.off("emergency_done", handleEnableEmergency);
      socket.off("reset_done", handleEnableReset);
    };
  }, [socket, handleStep, handleEnableReset, handleEnableEmergency, handleEnableZeroref]);


  const fetchData = async () => {
    setLoading(true);
    api.getJSON('dac_params').then(async (resJSON) => {
      console.log(':response:', resJSON);
      if ((parseFloat(resJSON.resp.A.pot) > 0) || (parseFloat(resJSON.resp.A.not) < 0)) {
        setZeroRef(false);
      }
      else {
        setZeroRef(true);
      }
      setLoading(false);
    })
      .catch((e) => {
        console.log(e);
        setLoading(false);
      });
  }

  useFocusEffect(
    React.useCallback(() => {
      fetchData();
    }, [])  //console.log("emergency, reset, zeroref ", emergency, reset, zeroref);
  );

  return (
    <>
      <ImageBackground style={styles.imgBg} width={width} source={require('../../img/bg.png')}>
        <View style={styles.containerStart}>
          <Stats location="MANUAL" navigation={navigation} />
          <View style={[styles.rowBetween, styles.itemsStart, styles.pt60, styles.px20, styles.flex1]}>
            <View style={[styles.flex3, styles.rowCenter, styles.itemsStretch]}>
              <TouchableOpacity style={[styles.mr10, styles.manualLeft]} onPress={() => { setDirection(1); }}>
                <LinearGradient colors={direction == 1 ? [COLORS.ctrlActive1, COLORS.ctrlActive2] : [COLORS.ctrlInactive1, COLORS.ctrlInactive2]} style={styles.manualInner}>
                  <svg className="dirIcon" width="80" height="196" xmlns="http://www.w3.org/2000/svg">
                    <g transform="translate(-109.000000, -33.000000)" fill={direction == 1 ? "#2891B9" : "#FFFFFF33"}>
                      <path d="M109,61.0740898 L179.093363,33 L189,109.212617 L169.306005,97.5499239 C160.875838,112.352739 158.130953,127.725392 161.071348,143.667884 C164.011744,159.610376 173.321294,173.207619 189,184.459613 L170.541039,229 C138.516464,213.22728 119.072998,189.319536 112.210642,157.276768 C105.348286,125.234001 109.677573,97.1084378 125.198504,72.9000792 L109,61.0740898 Z" id="arrow-l"></path>
                    </g>
                  </svg>
                </LinearGradient>
              </TouchableOpacity>
              <View style={[styles.itemsCenter, styles.justifyCenter]}>
                <Image source={require('../../img/logo2.png')} style={[styles.logoManual, styles.mb40]} />
                <TouchableOpacity style={[styles.w100p, { opacity: (jog || !zeroRef || emergency || reset || zeroref) ? 0.3 : 1 }]} disabled={jog || !zeroRef || emergency || reset || zeroref} onPress={() => {
                  handleSend('goToZero', {}),
                    dispatch(setEmergency(false, false, true))
                }}>
                  <LinearGradient colors={[COLORS.gray1, COLORS.gray2]} style={styles.btn}>
                    <Text style={styles.btnTxtRed}>ZERO REF</Text>
                  </LinearGradient>
                </TouchableOpacity>
              </View>
              <TouchableOpacity style={[styles.ml10, styles.manualRight]} onPress={() => { setDirection(0); }}>
                <LinearGradient colors={direction == 0 ? [COLORS.ctrlActive1, COLORS.ctrlActive2] : [COLORS.ctrlInactive1, COLORS.ctrlInactive2]} style={styles.manualInner}>
                  <svg className="dirIcon" width="80" height="196" xmlns="http://www.w3.org/2000/svg">
                    <g transform="translate(-254.000000, -33.000000)" fill={direction == 0 ? "#2891B9" : "#FFFFFF33"}>
                      <path d="M254,61.0740898 L324.093363,33 L334,109.212617 L314.306005,97.5499239 C305.875838,112.352739 303.130953,127.725392 306.071348,143.667884 C309.011744,159.610376 318.321294,173.207619 334,184.459613 L315.541039,229 C283.516464,213.22728 264.072998,189.319536 257.210642,157.276768 C250.348286,125.234001 254.677573,97.1084378 270.198504,72.9000792 L254,61.0740898 Z" id="arrow-r" transform="translate(294.000000, 131.000000) scale(-1, 1) translate(-294.000000, -131.000000) "></path>
                    </g>
                  </svg>
                </LinearGradient>
              </TouchableOpacity>
            </View>
            <View style={[styles.flex1, styles.justifyStart]}>
              <View style={[styles.rowCenter, styles.well, styles.mb10]}>
                <TouchableOpacity style={[styles.flex1, { opacity: (zeroref || reset) ? 0.3 : 1 }]} disabled={zeroref || reset} onPress={() => { setMode('JOG'); }}>
                  <LinearGradient colors={mode == 'JOG' ? [COLORS.green1, COLORS.green2] : ['#0000', '#0000']} style={styles.btn0}>
                    <Text style={styles.btnTxtRed}>JOG</Text>
                  </LinearGradient>
                </TouchableOpacity>
                <TouchableOpacity style={[styles.flex1, { opacity: (zeroref || reset) ? 0.3 : 1 }]} disabled={mode == 'JOG' && action == 1 || zeroref || reset} onPress={() => {
                  handleSend('enable_step_mode', { "status": "1" });
                  setMode('STEP');
                }}>
                  <LinearGradient colors={mode == 'STEP' ? [COLORS.green1, COLORS.green2] : ['#0000', '#0000']} style={styles.btn0}>
                    <Text style={styles.btnTxtRed}>STEP</Text>
                  </LinearGradient>
                </TouchableOpacity>
              </View>

              {mode == 'JOG' &&
                <TouchableOpacity disabled={zeroref || emergency || reset} style={[styles.w100p, { opacity: (zeroref || emergency || reset) ? 0.3 : 1 }]} onPress={() => {
                  handleSend('jog_mode', { "dir": direction, "action": action == 0 ? 1 : 0 });
                  dispatch(setJog(action == 0 ? true : false));
                  setAction(action == 0 ? 1 : 0);
                }}>
                  <LinearGradient colors={action == 0 ? [COLORS.blue1, COLORS.blue2] : [COLORS.red1, COLORS.red2]} style={styles.btn}>
                    <Ionicons name="ios-checkmark-sharp" size={20} color="#fffa" style={styles.mr10} />
                    <Text style={styles.btnTxtRed}>{action == 0 ? 'START' : 'STOP'} JOG</Text>
                  </LinearGradient>
                </TouchableOpacity>
              }

              {mode == 'STEP' &&
                <>
                  <View style={[styles.rowCenter, styles.well, styles.mb10]}>
                    <TouchableOpacity disabled={zeroref} style={[styles.flex1, { opacity: zeroref ? 0.3 : 1 }]} onPress={() => { setPosition(0.1); }}>
                      <LinearGradient colors={position == 0.1 ? [COLORS.green1, COLORS.green2] : ['#0000', '#0000']} style={styles.btn0}>
                        <Text style={styles.btnTxtRed}>0.1</Text>
                      </LinearGradient>
                    </TouchableOpacity>
                    <TouchableOpacity disabled={zeroref} style={[styles.flex1, { opacity: zeroref ? 0.3 : 1 }]} onPress={() => { setPosition(0.01); }}>
                      <LinearGradient colors={position == 0.01 ? [COLORS.green1, COLORS.green2] : ['#0000', '#0000']} style={styles.btn0}>
                        <Text style={styles.btnTxtRed}>0.01</Text>
                      </LinearGradient>
                    </TouchableOpacity>
                    <TouchableOpacity disable={zeroref} style={[styles.flex1, { opacity: zeroref ? 0.3 : 1 }]} onPress={() => { setPosition(0.001); }}>
                      <LinearGradient colors={position == 0.001 ? [COLORS.green1, COLORS.green2] : ['#0000', '#0000']} style={styles.btn0}>
                        <Text style={styles.btnTxtRed}>0.001</Text>
                      </LinearGradient>
                    </TouchableOpacity>
                  </View>
                  <TouchableOpacity style={[styles.w100p, { opacity: moving || zeroref ? 0.3 : 1 }]} disabled={moving || zeroref} onPress={() => {
                    handleSend('step_mode', { "drive_id": 1, "position": direction == 1 ? position : 0 - position, "dir": direction });
                    setMoving(!moving);
                  }}>
                    <LinearGradient colors={[COLORS.blue1, COLORS.blue2]} style={styles.btn}>
                      <Ionicons name="ios-checkmark-sharp" size={20} color="#fffa" style={styles.mr10} />
                      <Text style={styles.btnTxtRed}>MOVE</Text>
                    </LinearGradient>
                  </TouchableOpacity>
                </>
              }
            </View>
          </View>
        </View>
      </ImageBackground>

      {modal &&
        <View style={styles.overlayWrap}>
          <View style={styles.overlayInner}>
            <View style={[styles.rowCenter, styles.mb25]}>
              <Ionicons name="ios-alert-circle" size={20} color="#fffa" style={styles.mr10} />
              <Text style={[styles.title1, { textAlign: 'center' }]}>System is in auto mode. Please stop the program to visit Manual screen.</Text>
            </View>
            <View style={styles.rowCenter}>
              <TouchableOpacity style={styles.mr15} onPress={() => { navigation.goBack(); }}>
                <LinearGradient colors={[COLORS.blue1, COLORS.blue2]} style={styles.btn}>
                  <Text style={styles.btnTxtRed}>BACK</Text>
                </LinearGradient>
              </TouchableOpacity>

              <TouchableOpacity style={{}} onPress={() => { navigation.navigate('AutoScreens', { screen: 'Auto' }); }}>
                <LinearGradient colors={[COLORS.blue1, COLORS.blue2]} style={styles.btn}>
                  <Text style={styles.btnTxtRed}>AUTO</Text>
                </LinearGradient>
              </TouchableOpacity>
            </View>
          </View>
        </View>
      }
    </>
  );
};

export default Manual;




